import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { handleError, handleSuccess } from "../utils";
import { ToastContainer } from "react-toastify";
import "./home.css";

function Home() {
    const [loggedInUser, setLoggedInUser] = useState("");
    const [userProfile, setUserProfile] = useState(null);
    const navigate = useNavigate();

    useEffect(() => {
        const username = localStorage.getItem("loggedInUser");

        console.log("username from localStorage:", username); // Log for debugging

        setLoggedInUser(username || "Utilisateur");

        if (!username) {
            handleError("Username not found, please log in again.");
            navigate("/login");
        } else {
            console.log("Fetching user profile for:", username); // Log for debugging
            fetchUserProfileByName(username);
        }
    }, [navigate]);

    const fetchUserProfileByName = async (username) => {
        try {
            const token = localStorage.getItem("token");
            if (!token) {
                handleError("Token not found, please log in again.");
                navigate("/login");
                return;
            }

            // Call the API to fetch the user profile by name
            const response = await axios.get(`http://localhost:5001/users/name/${username}`, {
                headers: { Authorization: `Bearer ${token}` },
            });

            // Check if the API response is successful
            if (response.data.success) {
                setUserProfile(response.data.user);
            } else {
                handleError("User not found");
            }
        } catch (error) {
            console.error("API Error:", error.response?.data || error.message);
            handleError("Failed to fetch user profile");
        }
    };

    const handleLogout = () => {
        // User logout logic
        localStorage.removeItem("token");
        localStorage.removeItem("loggedInUser");
        handleSuccess("User Logged out");
        setTimeout(() => {
            navigate("/login");
        }, 1000);
    };

    return (
        <div className="home-container">
            <div className="sidebar">
                <h2>Dashboard</h2>
                <ul>
                    <li><a href="/home">Home</a></li>
                    <li><a href="/profile">Profile</a></li>
                    <li><a href="/products">Products</a></li>
                </ul>
            </div>

            <div className="main-content">
                <div className="header">
                    <h1>Welcome, {loggedInUser}</h1>
                    <button onClick={handleLogout} className="logout-btn">Logout</button>
                </div>

                {userProfile ? (
                    <div className="profile-section">
                        <h3>User Profile</h3>
                        <div className="profile-info">
                            <p><strong>Name:</strong> {userProfile.name}</p>
                            <p><strong>Email:</strong> {userProfile.email}</p>
                            <p><strong>Role:</strong> {userProfile.role}</p>
                        </div>
                    </div>
                ) : (
                    <p>Loading profile...</p>
                )}

                <ToastContainer />
            </div>
        </div>
    );
}

export default Home;
